mapper.update:
update kh_user_drug set status = #{status,jdbcType=SMALLINT},
reminder_start_date = #{reminderStartDate,jdbcType=TIMESTAMP},
update_time = now() where id = #{id,jdbcType=BIGINT}

mapper.select:
select id, user_id, drug_id, drug_name, status, drug_form, drug_unit_type, drug_unit_value,
start_date, end_date, reminder_start_date, frequency_type, days_interval, days_inweek,
times_aday, quantity, notes, create_time, update_time
from kh_user_drug
where user_id = #{userId,jdbcType=BIGINT}
and ( LOWER(drug_name) = LOWER(#{drugName,jdbcType=VARCHAR})

  or drug_id = #{drugId,jdbcType=BIGINT}
 )
